svg.script:
var data = [
  { 
    title: "مساحة إعلانية متاحة", 
    desc: 'تواصل مع إدارة "صوان" لحجز هذه المساحة', 
    align: "end"     // RTL: يبدأ من اليمين
  },
  { 
    title: "Advertising space available", 
    desc: "Contact Siwane management to reserve this space", 
    align: "start"   // LTR: يبدأ من اليسار
  }
];

var mainEl = document.getElementById("text-main");
var subEl = document.getElementById("text-sub");
var index = 0;
var busy = false; // لمنع التداخل

// دالة كتابة حرف بحرف مع مؤشر
function typeText(el, text, speed, callback) {
  var i = 0;
  el.textContent = "";
  function addChar() {
    if (i < text.length) {
      el.textContent = text.substring(0, i + 1) + "|";
      i++;
      setTimeout(addChar, speed);
    } else {
      el.textContent = text; // إزالة المؤشر بعد الانتهاء
      if (callback) callback();
    }
  }
  addChar();
}

// عرض جملة كاملة (عنوان + وصف)
function showItem(item, done) {
  // ضبط المحاذاة حسب اللغة
  mainEl.setAttribute("text-anchor", item.align);
  subEl.setAttribute("text-anchor", item.align);

  typeText(mainEl, item.title, 80, function() {
    typeText(subEl, item.desc, 45, function() {
      if (done) done();
    });
  });
}

// الانتقال إلى الجملة التالية
function next() {
  if (busy) return;
  busy = true;
  var item = data[index % 2];
  showItem(item, function() {
    // بعد انتهاء الكتابة، اترك النص ظاهراً 5 ثوانٍ
    setTimeout(function() {
      mainEl.textContent = "";
      subEl.textContent = "";
      busy = false;
      index++;
      // فاصل قصير ثم ابدأ الجملة التالية
      setTimeout(next, 300);
    }, 5000);
  });
}

// بدء الحلقة
next();
